args.command:
cd /opt/dec-bench/eval-core && node -e "
const { createClient } = require('@clickhouse/client');
const client = createClient({ host: 'localhost', port: 8123 });
async function run() {
  const r = await client.query({ query: 'SELECT count() AS n FROM analytics.events', format: 'JSONEachRow' });
  const rows = await r.json();
  console.log(JSON.stringify(rows));
  await client.close();
}
run().catch(e => { console.error(e); process.exit(1); });
"

